// 1. Initialize the stored values in context if they don't exist yet
const storedValues = context.get('storedValues') || {
    FL: null,
    FR: null,
    RL: null,
    RR: null
};

// 2. Update stored values with whatever comes in the current message
// Using optional chaining (?.) to prevent crashes if FSU_data or RSU_data is missing
if (msg.payload && typeof msg.payload === 'object') {
    if (msg.payload.FSU_data?.LSuspension !== undefined) storedValues.FL = msg.payload.FSU_data.LSuspension;
    if (msg.payload.FSU_data?.RSuspension !== undefined) storedValues.FR = msg.payload.FSU_data.RSuspension;
    if (msg.payload.RSU_data?.LSuspension !== undefined) storedValues.RL = msg.payload.RSU_data.LSuspension;
    if (msg.payload.RSU_data?.RSuspension !== undefined) storedValues.RR = msg.payload.RSU_data.RSuspension;
}

// 3. Save the updated values back to the node's context
context.set('storedValues', storedValues);

// 4. Extract the valid numeric values to calculate the average
const validValues = Object.values(storedValues).filter(v => v !== null && typeof v === 'number');

// 5. Calculate average only if we have at least one value
if (validValues.length > 0) {
    const sum = validValues.reduce((acc, curr) => acc + curr, 0);
    const average = sum / validValues.length;

    // Output the average and how many active sensors contributed to it
    msg.payload = {
        average: Number(average.toFixed(2)), // Rounds to 2 decimal places
        activeCount: validValues.length,
        currentValues: storedValues
    };
    return msg;
}

// If no data has been received yet, do nothing
return null;

// 1. Read user inputs and toggle state from the flow context (set by Dashboard 2.0)
// We default 'isEnabled' to true so data flows until explicitly turned off
const isEnabled = flow.get("ch1_enable");
const channelName = flow.get("ch1_name");
const dataRoute = flow.get("ch1_route");

// 2. If the channel is disabled via the dashboard, drop the message immediately
if (!isEnabled) {
    return null;
}

// 3. Helper function to extract nested object values using a string path
function getNestedValue(obj, path) {
    if (!path || typeof obj !== 'object') return undefined;

    // Normalize path to handle arrays (turns "data[0].x" into "data.0.x")
    const normalizedPath = path.replace(/\[(\w+)\]/g, '.$1');

    // Drill down into the payload object using the user's string route
    return normalizedPath.split('.').reduce((acc, part) => {
        return (acc !== null && acc !== undefined) ? acc[part] : undefined;
    }, obj);
}

// 4. Extract the specific data point from the incoming message
const extractedValue = getNestedValue(msg.payload, dataRoute);

// 5. Validate and format output
if (extractedValue !== undefined && extractedValue !== null && extractedValue !== "") {

    const numericValue = Number(extractedValue);

    // Ensure it is a valid number (not NaN) before sending
    if (!isNaN(numericValue)) {
        msg.topic = channelName;
        msg.payload = numericValue;
        return msg;
    }
}

// If data is missing, undefined, or NaN, silently drop the message
return null;

