// 1. Intercept the Clear command from the UI
if (msg.payload === "CLEAR_DATA") {
    context.set('retainedData', {});
    context.set('lastUpdated', 'Cleared');
    msg.payload = {};
    msg.lastUpdated = 'Cleared';
    return msg;
}

// 2. INFINITE LOOP BREAKER
// If the message has our custom 'lastUpdated' flag, it means it just 
// passed through the UI node. We drop it here so it doesn't loop.
if (msg.lastUpdated) {
    return null; 
}

// 3. Normal data processing
let storedData = context.get('retainedData') || {};
let incomingTime = msg.timestamp || new Date().toLocaleTimeString();

for (let message in msg.payload) {
    if (typeof msg.payload[message] === 'object' && msg.payload[message] !== null) {
        if (!storedData[message]) {
            storedData[message] = { signals: {}, timestamp: "" };
        }
        storedData[message].signals = { ...storedData[message].signals, ...msg.payload[message] };
        storedData[message].timestamp = incomingTime;
    }
}

context.set('retainedData', storedData);
msg.payload = storedData;
msg.lastUpdated = incomingTime; 

return msg;
